var surah021 = {
  number: 21,
  nameArabic: "al-Anbiya",
  nameEnglish: "Al-Anbiya",
  meaning: "The Prophets",
  totalAyahs: 112,
  ayahs: [
    { number: 1, arabic: "ٱقْتَرَبَ لِلنَّاسِ حِسَابُهُمْ وَهُمْ فِى غَفْلَةٍۢ مُّعْرِضُونَ", transliteration: "Iqtaraba lilnnasi hisabuhum wahum fee ghaflatin muAAridoona", transliterationB: "Iqtaraba linnaasi hisaa buhum wa hum fee ghaflatim mu'ridoon", english: "Closer and closer to mankind comes their Reckoning: yet they heed not and they turn away", romanUrdu: "Qareeb aa gaya hai logon ke hisaab ka waqt, aur woh hain ke gaflat mein mooh moadey huey hain" },
    { number: 2, arabic: "مَا يَأْتِيهِم مِّن ذِكْرٍۢ مِّن رَّبِّهِم مُّحْدَثٍ إِلَّا ٱسْتَمَعُوهُ وَهُمْ يَلْعَبُونَ", transliteration: "Ma yateehim min thikrin min rabbihim muhdathin illa istamaAAoohu wahum yalAAaboona", transliterationB: "Maa yaateehim min zikrim mir Rabbihim muhdasin illas tama'oohu wa hum yal'aboon", english: "Never comes (aught) to them of a renewed Message from their Lord, but they listen to it as in jest", romanUrdu: "Unke paas jo taaza naseehat bhi unke Rubb ki taraf se aati hai usko be-takalluf sunte hain aur khel mein padey rehte hain" },
    { number: 3, arabic: "لَاهِيَةًۭ قُلُوبُهُمْ ۗ وَأَسَرُّوا۟ ٱلنَّجْوَى ٱلَّذِينَ ظَلَمُوا۟ هَلْ هَٰذَآ إِلَّا بَشَرٌۭ مِّثْلُكُمْ ۖ أَفَتَأْتُونَ ٱلسِّحْرَ وَأَنتُمْ تُبْصِرُونَ", transliteration: "Lahiyatan quloobuhum waasarroo alnnajwa allatheena thalamoo hal hatha illa basharun mithlukum afatatoona alssihra waantum tubsiroona", transliterationB: "Laahiyatan quloobuhum; wa asarrun najwal lazeena zalamoo hal haazaa illaa basharum mislukum afataa toonas sihra wa antum tubsiroon", english: "Their hearts toying as with trifles. The wrong-doers conceal their private counsels, (saying), \"Is this (one) more than a man like yourselves? Will ye go to witchcraft with your eyes open", romanUrdu: "Dil unke (dusri hi fikron mein) munhamik hain aur zalim aapas mein sargoshiyan(whisper) karte hain ke “yeh shaks aakhir tum jaisa ek bashar (Insaan) hi to hai, phir kya tum aankhon dekhte jaadu ke phanday mein phas jaogey?”" },
    { number: 4, arabic: "قَالَ رَبِّى يَعْلَمُ ٱلْقَوْلَ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ", transliteration: "Qala rabbee yaAAlamu alqawla fee alssamai waalardi wahuwa alssameeAAu alAAaleemu", transliterationB: "Qaala Rabbee ya'lamul qawla fis samaaa'i wal ardi wa Huwas Samee'ul Aleem", english: "Say: \"My Lord knoweth (every) word (spoken) in the heavens and on earth: He is the One that heareth and knoweth (all things)", romanUrdu: "Rasool ne kaha, mera Rubb har us baat ko jaanta hai jo aasman aur zameen mein ki jaye, woh sami(sunne wala) aur aleem (jaanne wala) hai" },
    { number: 5, arabic: "بَلْ قَالُوٓا۟ أَضْغَٰثُ أَحْلَٰمٍۭ بَلِ ٱفْتَرَىٰهُ بَلْ هُوَ شَاعِرٌۭ فَلْيَأْتِنَا بِـَٔايَةٍۢ كَمَآ أُرْسِلَ ٱلْأَوَّلُونَ", transliteration: "Bal qaloo adghathu ahlamin bali iftarahu bal huwa shaAAirun falyatina biayatin kama orsila alawwaloona", transliterationB: "Bal qaalooo adghaasu ahlaamim balif taraahu bal huwa shaa'irun falyaatinaa bi Aayatin kamaa ursilal awwaloon", english: "Nay,\" they say, \"(these are) medleys of dream! - Nay, He forged it! - Nay, He is (but) a poet! Let him then bring us a Sign like the ones that were sent to (Prophets) of old", romanUrdu: "Woh kehte hain “balke yeh paraganda (incoherent) khwab hai , balke yeh iski mann-ghadath hai, balke yeh shaks shayar hai warna yeh laye koi nishani jis tarah purane zamane ke Rasool nishaniyon ke saath bheje gaye thay”" },
    { number: 6, arabic: "مَآ ءَامَنَتْ قَبْلَهُم مِّن قَرْيَةٍ أَهْلَكْنَٰهَآ ۖ أَفَهُمْ يُؤْمِنُونَ", transliteration: "Ma amanat qablahum min qaryatin ahlaknaha afahum yuminoona", transliterationB: "Maaa aaamanat qablahum min qaryatin ahlaknaahaa a-fahum yu'minoon", english: "(As to those) before them, not one of the populations which We destroyed believed: will these believe", romanUrdu: "Halaanke inse pehle koi basti bhi, jisey humne halaak kiya, iman na layi, ab kya yeh iman layenge" },
    { number: 7, arabic: "وَمَآ أَرْسَلْنَا قَبْلَكَ إِلَّا رِجَالًۭا نُّوحِىٓ إِلَيْهِمْ ۖ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ", transliteration: "Wama arsalna qablaka illa rijalan noohee ilayhim faisaloo ahla alththikri in kuntum la taAAlamoona", transliterationB: "Wa maaa arsalnaa qablaka illaa rijaalan nooheee ilaihim fas'aloo ahlaz zikri in kuntum laa ta'lamoon", english: "Before thee, also, the messengers We sent were but men, to whom We granted inspiration: If ye realise this not, ask of those who possess the Message", romanUrdu: "Aur (aey Muhammad), tumse pehle bhi humne Insaano hi ko Rasool bana kar bheja tha jinpar hum wahee (revelation) kiya karte thay, Tum log agar ilm nahin rakhte to ehle kitaab se pooch lo" },
    { number: 8, arabic: "وَمَا جَعَلْنَٰهُمْ جَسَدًۭا لَّا يَأْكُلُونَ ٱلطَّعَامَ وَمَا كَانُوا۟ خَٰلِدِينَ", transliteration: "Wama jaAAalnahum jasadan la yakuloona alttaAAama wama kanoo khalideena", transliterationB: "Wa maa ja'alnaahum jasadal laa yaakuloonat ta'aama wa maa kaanoo khaalideen", english: "Nor did We give them bodies that ate no food, nor were they exempt from death", romanUrdu: "Un Rasoolon ko humne koi aisa jism nahin diya tha ke woh khate na hon, aur na woh sadaa (hamesha) jeenay waley thay" },
    { number: 9, arabic: "ثُمَّ صَدَقْنَٰهُمُ ٱلْوَعْدَ فَأَنجَيْنَٰهُمْ وَمَن نَّشَآءُ وَأَهْلَكْنَا ٱلْمُسْرِفِينَ", transliteration: "Thumma sadaqnahumu alwaAAda faanjaynahum waman nashao waahlakna almusrifeena", transliterationB: "summa sadaqnaa humul wa'da fa-anjainaahum wa man nashaaa'u wa ahlaknal musrifeen", english: "In the end We fulfilled to them Our Promise, and We saved them and those whom We pleased, but We destroyed those who transgressed beyond bounds", romanUrdu: "Phir dekhlo ke aakhir e kaar humne unke saath apne wadey poorey kiye, aur unhein aur jis jis ko humne chaha bacha liya, aur hadd se guzar janey walon ko halaak kardiya" },
    { number: 10, arabic: "لَقَدْ أَنزَلْنَآ إِلَيْكُمْ كِتَٰبًۭا فِيهِ ذِكْرُكُمْ ۖ أَفَلَا تَعْقِلُونَ", transliteration: "Laqad anzalna ilaykum kitaban feehi thikrukum afala taAAqiloona", transliterationB: "Laqad anzalnaaa ilaikum Kitaaban feehi zikrukum afalaa ta'qiloon", english: "We have revealed for you (O men!) a book in which is a Message for you: will ye not then understand", romanUrdu: "Logon, humne tumhari taraf ek aisi kitaab bheji hai jismein tumhara hi zikr hai, kya tum samajhte nahin ho" },
    { number: 11, arabic: "وَكَمْ قَصَمْنَا مِن قَرْيَةٍۢ كَانَتْ ظَالِمَةًۭ وَأَنشَأْنَا بَعْدَهَا قَوْمًا ءَاخَرِينَ", transliteration: "Wakam qasamna min qaryatin kanat thalimatan waanshana baAAdaha qawman akhareena", transliterationB: "Wa kam qasamnaa min qaryatin kannat zaalimatanw wa anshadnaa ba'dahaa qawman aakhareen", english: "How many were the populations We utterly destroyed because of their iniquities, setting up in their places other peoples", romanUrdu: "Kitni hi zalim bastiyan hain jinko humne pees kar rakh diya aur unke baad dusri kisi qaum ko uthaya" },
    { number: 12, arabic: "فَلَمَّآ أَحَسُّوا۟ بَأْسَنَآ إِذَا هُم مِّنْهَا يَرْكُضُونَ", transliteration: "Falamma ahassoo basana itha hum minha yarkudoona", transliterationB: "Falammaaa ahassoo baasanaaa izaaa hum minhaa yarkudoon", english: "Yet, when they felt Our Punishment (coming), behold, they (tried to) flee from it", romanUrdu: "Jab unko hamara azaab mehsoos hua to lagey wahan se bhaagne" },
    { number: 13, arabic: "لَا تَرْكُضُوا۟ وَٱرْجِعُوٓا۟ إِلَىٰ مَآ أُتْرِفْتُمْ فِيهِ وَمَسَٰكِنِكُمْ لَعَلَّكُمْ تُسْـَٔلُونَ", transliteration: "La tarkudoo wairjiAAoo ila ma otriftum feehi wamasakinikum laAAallakum tusaloona", transliterationB: "Laa tarkudoo warji'ooo ilaa maaa utriftum feehe wa masaakinikum la'allakum tus'aloon", english: "Flee not, but return to the good things of this life which were given you, and to your homes in order that ye may be called to account", romanUrdu: "(kaha gaya) “bhaago nahin, jao apne unhi gharon mein aur aesh ke samaano mein jinke andar tum chain kar rahey thay, shayad ke tumse poocha jaye”" },
    { number: 14, arabic: "قَالُوا۟ يَٰوَيْلَنَآ إِنَّا كُنَّا ظَٰلِمِينَ", transliteration: "Qaloo ya waylana inna kunna thalimeena", transliterationB: "Qaaloo yaa wailanaaa innaa kunnaa zaalimeen", english: "They said: \"Ah! woe to us! We were indeed wrong-doers", romanUrdu: "Kehne lagey “haye hamari kambakhti, beshak hum khatawaar thay”" },
    { number: 15, arabic: "فَمَا زَالَت تِّلْكَ دَعْوَىٰهُمْ حَتَّىٰ جَعَلْنَٰهُمْ حَصِيدًا خَٰمِدِينَ", transliteration: "Fama zalat tilka daAAwahum hatta jaAAalnahum haseedan khamideena", transliterationB: "Famaa zaalat tilka da'waahum hattaa ja'alnaahum haseedan khaamideen", english: "And that cry of theirs ceased not, till We made them as a field that is mown, as ashes silent and quenched", romanUrdu: "Aur woh yahi pukarte rahey yahan tak ke humne unko khalyan (threshed/field that is reaped) kardiya , zindagi ka ek sharara tak unmein na raha (leaving no spark of life in them)" },
    { number: 16, arabic: "وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا لَٰعِبِينَ", transliteration: "Wama khalaqna alssamaa waalarda wama baynahuma laAAibeena", transliterationB: "Wa maa khalaqnas samaaa'a wal arda wa maa bainahumaa laa'ibeen", english: "Not for (idle) sport did We create the heavens and the earth and all that is between", romanUrdu: "Humne is aasman aur zameen ko aur jo kuch bhi inmein hai kuch khel ke taur par nahin banaya hai" },
    { number: 17, arabic: "لَوْ أَرَدْنَآ أَن نَّتَّخِذَ لَهْوًۭا لَّٱتَّخَذْنَٰهُ مِن لَّدُنَّآ إِن كُنَّا فَٰعِلِينَ", transliteration: "Law aradna an nattakhitha lahwan laittakhathnahu min ladunna in kunna faAAileena", transliterationB: "Law aradnaaa an nattakhiza lahwal lat takhaznaahu mil ladunnaaa in kunnaa faa'ileen", english: "If it had been Our wish to take (just) a pastime, We should surely have taken it from the things nearest to Us, if We would do (such a thing)", romanUrdu: "Agar hum koi khilona banan chahte aur bas yahi kuch humein karna hota to apne hi paas se kar letey" },
    { number: 18, arabic: "بَلْ نَقْذِفُ بِٱلْحَقِّ عَلَى ٱلْبَٰطِلِ فَيَدْمَغُهُۥ فَإِذَا هُوَ زَاهِقٌۭ ۚ وَلَكُمُ ٱلْوَيْلُ مِمَّا تَصِفُونَ", transliteration: "Bal naqthifu bialhaqqi AAala albatili fayadmaghuhu faitha huwa zahiqun walakumu alwaylu mimma tasifoona", transliterationB: "Bal naqzifu bilhaqqi 'alal baatili fa yadmaghuhoo fa izaa huwa zaahiq; wa lakumul wailu mimmaa tasifoon", english: "Nay, We hurl the Truth against falsehood, and it knocks out its brain, and behold, falsehood doth perish! Ah! woe be to you for the (false) things ye ascribe (to Us)", romanUrdu: "Magar hum to baatil par haqq ki chot lagate hain jo uska sar todh deti hai aur woh dekhte dekhte mitt jata hai, aur tumhare liye tabahi hai un baaton ki wajah se jo tum banate ho" },
    { number: 19, arabic: "وَلَهُۥ مَن فِى ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَنْ عِندَهُۥ لَا يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِۦ وَلَا يَسْتَحْسِرُونَ", transliteration: "Walahu man fee alssamawati waalardi waman AAindahu la yastakbiroona AAan AAibadatihi wala yastahsiroona", transliterationB: "Wa lahoo man fis samaawaati wal ard; wa man 'indahoo laa yastakbiroona 'an 'ibaada tihee wa laa yastahsiroon", english: "To Him belong all (creatures) in the heavens and on earth: Even those who are in His (very) Presence are not too proud to serve Him, nor are they (ever) weary (of His service)", romanUrdu: "Zameen aur aasmano mein jo makhlooq bhi hai Allah ki hai aur jo (Farishtey) uske paas hain woh na apne aap ko bada samajh kar uski bandagi se sartabi karte hain aur na malool (weary /tire) hotey hain" },
    { number: 20, arabic: "يُسَبِّحُونَ ٱلَّيْلَ وَٱلنَّهَارَ لَا يَفْتُرُونَ", transliteration: "Yusabbihoona allayla waalnnahara la yafturoona", transliterationB: "Yusabbihoona laila wannahaara laa yafturoon", english: "They celebrate His praises night and day, nor do they ever flag or intermit", romanUrdu: "Shab-o-roz uski tasbeeh karte rehte hain, dum nahin letey" },
    { number: 21, arabic: "أَمِ ٱتَّخَذُوٓا۟ ءَالِهَةًۭ مِّنَ ٱلْأَرْضِ هُمْ يُنشِرُونَ", transliteration: "Ami ittakhathoo alihatan mina alardi hum yunshiroona", transliterationB: "Amit takhazooo aalihatam minal ardi hum yunshiroon", english: "Or have they taken (for worship) gods from the earth who can raise (the dead)", romanUrdu: "Kya in logon ke banaye huey arzi khuda aisey hain ke (be-jaan ko jaan baksh kar) utha khada karte hon" },
    { number: 22, arabic: "لَوْ كَانَ فِيهِمَآ ءَالِهَةٌ إِلَّا ٱللَّهُ لَفَسَدَتَا ۚ فَسُبْحَٰنَ ٱللَّهِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ", transliteration: "Law kana feehima alihatun illa Allahu lafasadata fasubhana Allahi rabbi alAAarshi AAamma yasifoona", transliterationB: "Law kaana feehimaaa aalihatun illal laahu lafasadataa; fa-Subhaanal laahi Rabbil 'Arshi 'ammaa yasifoon", english: "If there were, in the heavens and the earth, other gods besides Allah, there would have been confusion in both! but glory to Allah, the Lord of the Throne: (High is He) above what they attribute to Him", romanUrdu: "Agar aasman o zameen mein ek Allah ke siwa dusre khuda bhi hotey to (zameen aur aasman) dono ka nizam bigad jata. Pas paak hai Allah Rabbul arsh un baaton se jo yeh log bana rahey hain" },
    { number: 23, arabic: "لَا يُسْـَٔلُ عَمَّا يَفْعَلُ وَهُمْ يُسْـَٔلُونَ", transliteration: "La yusalu AAamma yafAAalu wahum yusaloona", transliterationB: "Laa yus'alu 'ammaa yaf'alu wa hum yus'aloon", english: "He cannot be questioned for His acts, but they will be questioned (for theirs)", romanUrdu: "Woh apne kaamon ke liye (kisi ke aagey) jawab-de nahin hai aur sab jawab-de hain" },
    { number: 24, arabic: "أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةًۭ ۖ قُلْ هَاتُوا۟ بُرْهَٰنَكُمْ ۖ هَٰذَا ذِكْرُ مَن مَّعِىَ وَذِكْرُ مَن قَبْلِى ۗ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ ٱلْحَقَّ ۖ فَهُم مُّعْرِضُونَ", transliteration: "Ami ittakhathoo min doonihi alihatan qul hatoo burhanakum hatha thikru man maAAiya wathikru man qablee bal aktharuhum la yaAAlamoona alhaqqa fahum muAAridoona", transliterationB: "Amit takhazoo min doonihee aalihatan qul haatoo burhaanakum haaza zikru mam ma'iya wa zikru man qablee; bal aksaruhum laa ya'lamoonal haqqa fahum mu'ridoon", english: "Or have they taken for worship (other) gods besides him? Say, \"Bring your convincing proof: this is the Message of those with me and the Message of those before me.\" But most of them know not the Truth, and so turn away", romanUrdu: "Kya usey chodh kar inhon ne dusre khuda bana liye hain? (Aey Muhammad) inse kaho ke “lao apni daleel,yeh kitaab bhi maujood hai jismein mere daur ke logon ke liye naseehat hai aur woh kitaabein bhi maujood hain jin mein mujhse pehle logon ke liye naseehat thi” magar un mein se aksar log haqeeqat se bekhabar hain, is liye mooh moadey huey hain" },
    { number: 25, arabic: "وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ إِلَّا نُوحِىٓ إِلَيْهِ أَنَّهُۥ لَآ إِلَٰهَ إِلَّآ أَنَا۠ فَٱعْبُدُونِ", transliteration: "Wama arsalna min qablika min rasoolin illa noohee ilayhi annahu la ilaha illa ana faoAAbudooni", transliterationB: "Wa maaa arsalnaa min qablika mir Rasoolin illaa nooheee ilaihi annahoo laaa ilaaha illaaa Ana fa'budoon", english: "Not a messenger did We send before thee without this inspiration sent by Us to him: that there is no god but I; therefore worship and serve Me", romanUrdu: "Humne tumse pehle jo Rasool bhi bheja hai usko yahi wahee ki hai ke mere siwa koi khuda nahin hai, pas tumlog meri hi bandagi karo" },
    { number: 26, arabic: "وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَٰنُ وَلَدًۭا ۗ سُبْحَٰنَهُۥ ۚ بَلْ عِبَادٌۭ مُّكْرَمُونَ", transliteration: "Waqaloo ittakhatha alrrahmanu waladan subhanahu bal AAibadun mukramoona", transliterationB: "Wa qaalut takhazar Rahmaanu waladan Subhaanah; bal 'ibaadum mkkramoon", english: "And they say: \"(Allah) Most Gracious has begotten offspring.\" Glory to Him! they are (but) servants raised to honour", romanUrdu: "Yeh kehte hain “rehman aulad rakhta hai” SubhanAllah , woh to banday hain jinhein izzat di gayi hai" },
    { number: 27, arabic: "لَا يَسْبِقُونَهُۥ بِٱلْقَوْلِ وَهُم بِأَمْرِهِۦ يَعْمَلُونَ", transliteration: "La yasbiqoonahu bialqawli wahum biamrihi yaAAmaloona", transliterationB: "Laa yasbiqoonahoo bil qawli wa hum bi amrihee ya'maloon", english: "They speak not before He speaks, and they act (in all things) by His Command", romanUrdu: "Uske huzoor badh kar nahin bolte aur bas uske hukum par amal karte hain" },
    { number: 28, arabic: "يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يَشْفَعُونَ إِلَّا لِمَنِ ٱرْتَضَىٰ وَهُم مِّنْ خَشْيَتِهِۦ مُشْفِقُونَ", transliteration: "YaAAlamu ma bayna aydeehim wama khalfahum wala yashfaAAoona illa limani irtada wahum min khashyatihi mushfiqoona", transliterationB: "Ya'lamu maa baina aideehim wa maa khalfahum wa laa yashfa'oona illaa limanir tadaa wa hum min khash yatihee mushfiqoon", english: "He knows what is before them, and what is behind them, and they offer no intercession except for those who are acceptable, and they stand in awe and reverence of His (Glory)", romanUrdu: "Jo kuch unke saamne hai usey bhi woh jaanta hai aur jo kuch unse ojhal hai ussey bhi woh bakhabar hai, woh kisi ki sifarish nahin karte bajuz uske jiske haqq mein sifarish sunne par Allah raazi ho, aur woh uske khauf se darey rehte hain" },
    { number: 29, arabic: "۞ وَمَن يَقُلْ مِنْهُمْ إِنِّىٓ إِلَٰهٌۭ مِّن دُونِهِۦ فَذَٰلِكَ نَجْزِيهِ جَهَنَّمَ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّٰلِمِينَ", transliteration: "Waman yaqul minhum innee ilahun min doonihi fathalika najzeehi jahannama kathalika najzee alththalimeena", transliterationB: "Wa mai yaqul minhum inneee ilaahum min doonihee fazaalika najzeehi Jahannam; kazaalika najziz zaalimeen", english: "If any of them should say, \"I am a god besides Him\", such a one We should reward with Hell: thus do We reward those who do wrong", romanUrdu: "Aur jo unmein se koi kehde ke Allah ke siwa main bhi ek khuda hoon, to usey hum jahannum ki saza dein, hamare haan zaalimon ka yahi badla hai" },
    { number: 30, arabic: "أَوَلَمْ يَرَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضَ كَانَتَا رَتْقًۭا فَفَتَقْنَٰهُمَا ۖ وَجَعَلْنَا مِنَ ٱلْمَآءِ كُلَّ شَىْءٍ حَىٍّ ۖ أَفَلَا يُؤْمِنُونَ", transliteration: "Awalam yara allatheena kafaroo anna alssamawati waalarda kanata ratqan fafataqnahuma wajaAAalna mina almai kulla shayin hayyin afala yuminoona", transliterationB: "Awalam yaral lazeena kafarooo annas samaawaati wal arda kaanataa ratqan faftaqnaahumaa wa ja'alnaa minal maaa'i kulla shai'in haiyin afalaa yu'minoon", english: "Do not the Unbelievers see that the heavens and the earth were joined together (as one unit of creation), before we clove them asunder? We made from water every living thing. Will they not then believe", romanUrdu: "Kya yeh log jinhon ne (Nabi ki baat maanney se) inkar kardiya hai gaur nahin karte ke yeh sab aasman aur zameen baham miley huey thay, phir humne inhein juda kiya, aur pani se har zinda cheez paida ki, kya woh (hamari is khallaqi ko) nahin maante" },
    { number: 31, arabic: "وَجَعَلْنَا فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِهِمْ وَجَعَلْنَا فِيهَا فِجَاجًۭا سُبُلًۭا لَّعَلَّهُمْ يَهْتَدُونَ", transliteration: "WajaAAalna fee alardi rawasiya an tameeda bihim wajaAAalna feeha fijajan subulan laAAallahum yahtadoona", transliterationB: "Wa ja'alnaa fil ardi rawaasiya an tameeda bihim wa ja'alnaa feehaa fijaajan subulal la'allahum yahtadoon", english: "And We have set on the earth mountains standing firm, lest it should shake with them, and We have made therein broad highways (between mountains) for them to pass through: that they may receive Guidance", romanUrdu: "Aur humne zameen mein pahad jamaa diye taa-ke woh unhein lekar dhulak na jaye, aur ismein kushada raahein bana di, shayad ke log apna raasta maloom karlein" },
    { number: 32, arabic: "وَجَعَلْنَا ٱلسَّمَآءَ سَقْفًۭا مَّحْفُوظًۭا ۖ وَهُمْ عَنْ ءَايَٰتِهَا مُعْرِضُونَ", transliteration: "WajaAAalna alssamaa saqfan mahfoothan wahum AAan ayatiha muAAridoona", transliterationB: "Wa ja'alnas samaaa'a saqfam mahfoozanw wa hum 'an Aayaatihaa mu'ridoon", english: "And We have made the heavens as a canopy well guarded: yet do they turn away from the Signs which these things (point to)", romanUrdu: "Aur humne aasman ko ek mehfooz chatt bana diya, magar ye hain ke iski nishaniyon ki taraf tawajju hi nahin karte" },
    { number: 33, arabic: "وَهُوَ ٱلَّذِى خَلَقَ ٱلَّيْلَ وَٱلنَّهَارَ وَٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّۭ فِى فَلَكٍۢ يَسْبَحُونَ", transliteration: "Wahuwa allathee khalaqa allayla waalnnahara waalshshamsa waalqamara kullun fee falakin yasbahoona", transliterationB: "Wa Huwal lazee khalaqal laila wannahaara washshamsa wal qamara kullun fee falakiny yashbahoon", english: "It is He Who created the Night and the Day, and the sun and the moon: all (the celestial bodies) swim along, each in its rounded course", romanUrdu: "Aur woh Allah hi hai jisne raat aur din banaye aur Suraj aur Chand ko paida kiya, sab ek ek falak mein tair rahey hain" },
    { number: 34, arabic: "وَمَا جَعَلْنَا لِبَشَرٍۢ مِّن قَبْلِكَ ٱلْخُلْدَ ۖ أَفَإِي۟ن مِّتَّ فَهُمُ ٱلْخَٰلِدُونَ", transliteration: "Wama jaAAalna libasharin min qablika alkhulda afain mitta fahumu alkhalidoona", transliterationB: "Wa maa ja'alnaa libasharim min qablikal khuld; afaimmitta fahumul khaalidoon", english: "We granted not to any man before thee permanent life (here): if then thou shouldst die, would they live permanently", romanUrdu: "Aur (aey Muhammad), hameshgi(eternity) to humne tumse pehle bhi kisi Insaan ke liye nahin rakkhi hai agar tum mar gaye to kya yeh log hamesha jeetay rahenge" },
    { number: 35, arabic: "كُلُّ نَفْسٍۢ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَنَبْلُوكُم بِٱلشَّرِّ وَٱلْخَيْرِ فِتْنَةًۭ ۖ وَإِلَيْنَا تُرْجَعُونَ", transliteration: "Kullu nafsin thaiqatu almawti wanablookum bialshsharri waalkhayri fitnatan wailayna turjaAAoona", transliterationB: "Kullu nafsin zaaa'iqatul mawt; wa nablookum bishsharri walkhairi fitnatanw wa ilainaa turja'oon", english: "Every soul shall have a taste of death: and We test you by evil and by good by way of trial. to Us must ye return", romanUrdu: "Har jaandaar ko maut ka maza chakhna hai, aur hum acchey aur burey halaat mein daal kar tum sabki aazmaish kar rahey hain, aakhir-e-kaar tumhein hamari hi taraf palatna hai" },
    { number: 36, arabic: "وَإِذَا رَءَاكَ ٱلَّذِينَ كَفَرُوٓا۟ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَٰذَا ٱلَّذِى يَذْكُرُ ءَالِهَتَكُمْ وَهُم بِذِكْرِ ٱلرَّحْمَٰنِ هُمْ كَٰفِرُونَ", transliteration: "Waitha raaka allatheena kafaroo in yattakhithoonaka illa huzuwan ahatha allathee yathkuru alihatakum wahum bithikri alrrahmani hum kafiroona", transliterationB: "Wa izaa ra aakal lazeena kafarooo iny-yattakhizoonaka illa huzuwaa; ahaazal lazee yazkuru aalihatakum wa hum bi zikrir Rahmaani hum kaafiroon", english: "When the Unbelievers see thee, they treat thee not except with ridicule. \"Is this,\" (they say), \"the one who talks of your gods?\" and they blaspheme at the mention of (Allah) Most Gracious", romanUrdu: "Yeh munkireen e haqq jab tumhein dekhte hain to tumhara mazaaq bana letey hain. Kehte hain “kya yeh hai woh shaks jo tumhare khudaon ka zikr kiya karta hai?” aur inka apna haal yeh hai ke rehman ke zikr se munkir hain" },
    { number: 37, arabic: "خُلِقَ ٱلْإِنسَٰنُ مِنْ عَجَلٍۢ ۚ سَأُو۟رِيكُمْ ءَايَٰتِى فَلَا تَسْتَعْجِلُونِ", transliteration: "Khuliqa alinsanu min AAajalin saoreekum ayatee fala tastaAAjiloona", transliterationB: "Khuliqal insaanu min 'ajal; sa ureekum Aayaatee falaa tasta'jiloon", english: "Man is a creature of haste: soon (enough) will I show you My Signs; then ye will not ask Me to hasten them", romanUrdu: "Insaan jald baaz makhlooq hai, abhi main tumko apni nishaniyan dikhaye deta hoon, jaldi na machao" },
    { number: 38, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alwaAAdu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal wa'du in kuntum saadiqeen", english: "They say: \"When will this promise come to pass, if ye are telling the truth", romanUrdu: "Yeh log kehte hain “aakhir yeh dhamki poori kab hogi agar tum sacchey ho”" },
    { number: 39, arabic: "لَوْ يَعْلَمُ ٱلَّذِينَ كَفَرُوا۟ حِينَ لَا يَكُفُّونَ عَن وُجُوهِهِمُ ٱلنَّارَ وَلَا عَن ظُهُورِهِمْ وَلَا هُمْ يُنصَرُونَ", transliteration: "Law yaAAlamu allatheena kafaroo heena la yakuffoona AAan wujoohihimu alnnara wala AAan thuhoorihim wala hum yunsaroona", transliterationB: "Law ya'lamul lazeena kafaroo heena laa yakuffoona 'anw wujoohihimun Naara wa laa 'an zuhoorihim wa laa hum yunsaroon", english: "If only the Unbelievers knew (the time) when they will not be able to ward off the fire from their faces, nor yet from their backs, and (when) no help can reach them", romanUrdu: "Kaash in kaafiron ko us waqt ka kuch ilam hota jabke yeh na apne mooh aag se bacha sakenge na apni peethein, aur na inko kahin se madad pahunchegi" },
    { number: 40, arabic: "بَلْ تَأْتِيهِم بَغْتَةًۭ فَتَبْهَتُهُمْ فَلَا يَسْتَطِيعُونَ رَدَّهَا وَلَا هُمْ يُنظَرُونَ", transliteration: "Bal tateehim baghtatan fatabhatuhum fala yastateeAAoona raddaha wala hum yuntharoona", transliterationB: "Bal taateehim baghtatan fatabhatuhum falaa yastatee'oona raddahaa wa laa hum yunzaroon", english: "Nay, it may come to them all of a sudden and confound them: no power will they have then to avert it, nor will they (then) get respite", romanUrdu: "Woh balaa (catastrophe) achanak aayegi aur inhein is tarah yaklakht (suddenly) daboch legi ke yeh na usko dafaa kar sakenge aur na inko lamha bhar mohlat hi mil sakegi" },
    { number: 41, arabic: "وَلَقَدِ ٱسْتُهْزِئَ بِرُسُلٍۢ مِّن قَبْلِكَ فَحَاقَ بِٱلَّذِينَ سَخِرُوا۟ مِنْهُم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ", transliteration: "Walaqadi istuhzia birusulin min qablika fahaqa biallatheena sakhiroo minhum ma kanoo bihi yastahzioona", transliterationB: "Wa laqadis tuhzi'a bi-Rusulim min qablika fahaaqa billazeena sakhiroo minhum maa kaanoo bihee yastahzi'oon", english: "Mocked were (many) messenger before thee; But their scoffers were hemmed in by the thing that they mocked", romanUrdu: "Mazaaq tumse pehle bhi Rasoolon ka udaya jaa chuka hai, magar unka mazaaq udane waley usi cheez ke pher mein aa kar rahey jiska woh mazaaq udatey thay" },
    { number: 42, arabic: "قُلْ مَن يَكْلَؤُكُم بِٱلَّيْلِ وَٱلنَّهَارِ مِنَ ٱلرَّحْمَٰنِ ۗ بَلْ هُمْ عَن ذِكْرِ رَبِّهِم مُّعْرِضُونَ", transliteration: "Qul man yaklaokum biallayli waalnnahari mina alrrahmani bal hum AAan thikri rabbihim muAAridoona", transliterationB: "Qul mai yakla 'ukum billaili wannahaari minar Rahmaan; bal hum 'an zikri Rabbihim mu'ridoon", english: "Say: \"Who can keep you safe by night and by day from (the Wrath of) (Allah) Most Gracious?\" Yet they turn away from the mention of their Lord", romanUrdu: "(Aey Muhammad), insey kaho, “kaun hai jo raat ko ya din ko tumhein rehman se bacha sakta ho?” magar yeh apne Rubb ki naseehat se mooh moad rahey hain" },
    { number: 43, arabic: "أَمْ لَهُمْ ءَالِهَةٌۭ تَمْنَعُهُم مِّن دُونِنَا ۚ لَا يَسْتَطِيعُونَ نَصْرَ أَنفُسِهِمْ وَلَا هُم مِّنَّا يُصْحَبُونَ", transliteration: "Am lahum alihatun tamnaAAuhum min doonina la yastateeAAoona nasra anfusihim wala hum minna yushaboona", transliterationB: "Am lahum aalihatun tamna'ulum min dooninaa; laa yastatee'oona nasra anfusihim wa laa hum minnna yus-haboon", english: "Or have they gods that can guard them from Us? They have no power to aid themselves, nor can they be defended from Us", romanUrdu: "Kya yeh kuch aise khuda rakhte hain jo hamare muqable mein inki himayat karein? Woh na to khud apni madad kar sakte hain aur na hamari hi taaeed unko haasil hai" },
    { number: 44, arabic: "بَلْ مَتَّعْنَا هَٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ طَالَ عَلَيْهِمُ ٱلْعُمُرُ ۗ أَفَلَا يَرَوْنَ أَنَّا نَأْتِى ٱلْأَرْضَ نَنقُصُهَا مِنْ أَطْرَافِهَآ ۚ أَفَهُمُ ٱلْغَٰلِبُونَ", transliteration: "Bal mattaAAna haolai waabaahum hatta tala AAalayhimu alAAumuru afala yarawna anna natee alarda nanqusuha min atrafiha afahumu alghaliboona", transliterationB: "Bal matta'naa haaa'ulaaa'i wa aabaaa'ahum hattaa taala 'alaihimul 'umur; afalaa yarawna anna naatil arda nanqusuhaa min atraafihaa; afahumul ghaaliboon", english: "Nay, We gave the good things of this life to these men and their fathers until the period grew long for them; See they not that We gradually reduce the land (in their control) from its outlying borders? Is it then they who will win", romanUrdu: "Asal baat yeh hai ke in logon ko aur inke aabaa o ajdaad (fore-fathers) ko hum zindagi ka sar o saamaan diye chale gaye yahan tak ke inko din lag gaye (until the period grew too long for them). Magar kya inhein nazar nahin aata ke hum zameen ko mukhtalif simton se ghataye chale aa rahey hain (shrinking its boundaries)? Phir kya yeh gaalib aa jayenge" },
    { number: 45, arabic: "قُلْ إِنَّمَآ أُنذِرُكُم بِٱلْوَحْىِ ۚ وَلَا يَسْمَعُ ٱلصُّمُّ ٱلدُّعَآءَ إِذَا مَا يُنذَرُونَ", transliteration: "Qul innama onthirukum bialwahyi wala yasmaAAu alssummu aldduAAaa itha ma yuntharoona", transliterationB: "Qul innamaaa unzirukum bilwahyi; wa laa yasma'us summud du'aaa'a izaa maa yunzaroon", english: "Say, \"I do but warn you according to revelation\": But the deaf will not hear the call, (even) when they are warned", romanUrdu: "Inse kehdo ke “main to wahee (revelation) ki bina par tumhein mutanabbeh (warn) kar raha hoon”. Magar behre pukaar ko nahin suna karte jabke unhein khabardaar kiya jaye" },
    { number: 46, arabic: "وَلَئِن مَّسَّتْهُمْ نَفْحَةٌۭ مِّنْ عَذَابِ رَبِّكَ لَيَقُولُنَّ يَٰوَيْلَنَآ إِنَّا كُنَّا ظَٰلِمِينَ", transliteration: "Walain massathum nafhatun min AAathabi rabbika layaqoolunna ya waylana inna kunna thalimeena", transliterationB: "Wa la'im massat hum nafhatum min 'azaabi Rabbika la yaqoolunna yaawailanaaa innnaa kunnaa zaalimeen", english: "If but a breath of the Wrath of thy Lord do touch them, they will then say, \"Woe to us! we did wrong indeed", romanUrdu: "Aur agar tere Rubb ka azaab zara sa inhein choo jaye to abhi cheekh utthein ke haaye hamari kambakhti, beshak hum khatawaar thay" },
    { number: 47, arabic: "وَنَضَعُ ٱلْمَوَٰزِينَ ٱلْقِسْطَ لِيَوْمِ ٱلْقِيَٰمَةِ فَلَا تُظْلَمُ نَفْسٌۭ شَيْـًۭٔا ۖ وَإِن كَانَ مِثْقَالَ حَبَّةٍۢ مِّنْ خَرْدَلٍ أَتَيْنَا بِهَا ۗ وَكَفَىٰ بِنَا حَٰسِبِينَ", transliteration: "WanadaAAu almawazeena alqista liyawmi alqiyamati fala tuthlamu nafsun shayan wain kana mithqala habbatin min khardalin atayna biha wakafa bina hasibeena", transliterationB: "Wa nada'ul mawaazeenal qista li Yawmil Qiyaamati falaa tuzlamu nafsun shai'aa; wa in kaana misqaala habbatim min khardalin atainaa bihaa; wa kafaa binaa haasibeen", english: "We shall set up scales of justice for the Day of Judgment, so that not a soul will be dealt with unjustly in the least, and if there be (no more than) the weight of a mustard seed, We will bring it (to account): and enough are We to take account", romanUrdu: "Qayamat ke roz hum theek theek toalne waley tarazu rakh dengey, phir kisi shaks par zarra barabar zulm na hoga. Jiska rai (mustard seed) ke daane ke barabar bhi kuch kiya dhara hoga woh hum saamne le aayenge aur hisaab lagane ke liye hum kafi hain" },
    { number: 48, arabic: "وَلَقَدْ ءَاتَيْنَا مُوسَىٰ وَهَٰرُونَ ٱلْفُرْقَانَ وَضِيَآءًۭ وَذِكْرًۭا لِّلْمُتَّقِينَ", transliteration: "Walaqad atayna moosa waharoona alfurqana wadiyaan wathikran lilmuttaqeena", transliterationB: "Wa laqad aatainaa Moosa wa haaroonal Furqaana wa diyaa'anw wa zikral lilmuttaqeen", english: "In the past We granted to Moses and Aaron the criterion (for judgment), and a Light and a Message for those who would do right", romanUrdu: "Pehle hum Moosa aur Haroon ko furqan(criteria) aur roshni aur “zikr” ata kar chuke hain un muttaqi logon ki bhalayi ke liye" },
    { number: 49, arabic: "ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ وَهُم مِّنَ ٱلسَّاعَةِ مُشْفِقُونَ", transliteration: "Allatheena yakhshawna rabbahum bialghaybi wahum mina alssaAAati mushfiqoona", transliterationB: "Allazeena yakhshawna Rabbahum bilghaibi wa hum minas Saa'ati mushfiqoon", english: "Those who fear their Lord in their most secret thoughts, and who hold the Hour (of Judgment) in awe", romanUrdu: "Jo bay-dekhe (bagair dekhe) apne Rubb se darein aur jinko (hisaab ki) us ghadi ka khatka laga hua hai" },
    { number: 50, arabic: "وَهَٰذَا ذِكْرٌۭ مُّبَارَكٌ أَنزَلْنَٰهُ ۚ أَفَأَنتُمْ لَهُۥ مُنكِرُونَ", transliteration: "Wahatha thikrun mubarakun anzalnahu afaantum lahu munkiroona", transliterationB: "Wa haazaa Zikrum Mubaarakun anzalnaah; afa antum lahoo munkiroon", english: "And this is a blessed Message which We have sent down: will ye then reject it", romanUrdu: "Aur ab yeh ba-barakat “zikr” humne (tumhare liye) nazil kiya hai phir kya tum isko qabool karne se inkaari ho" },
    { number: 51, arabic: "۞ وَلَقَدْ ءَاتَيْنَآ إِبْرَٰهِيمَ رُشْدَهُۥ مِن قَبْلُ وَكُنَّا بِهِۦ عَٰلِمِينَ", transliteration: "Walaqad atayna ibraheema rushdahu min qablu wakunna bihi AAalimeena", transliterationB: "Wa laqad aatainaaa Ibraaheema rushdahoo min qablu wa kunnaa bihee 'aalimeen", english: "We bestowed aforetime on Abraham his rectitude of conduct, and well were We acquainted with him", romanUrdu: "Ussey bhi pehle humne Ibrahim ko uski hosh-mandi bakshi thi aur hum usko khoob jantey thay" },
    { number: 52, arabic: "إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا هَٰذِهِ ٱلتَّمَاثِيلُ ٱلَّتِىٓ أَنتُمْ لَهَا عَٰكِفُونَ", transliteration: "Ith qala liabeehi waqawmihi ma hathihi alttamatheelu allatee antum laha AAakifoona", transliterationB: "Iz qaala li abeehi wa qawmihee maa haazihit tamaaseelul lateee antum lahee 'aakifoon", english: "Behold! he said to his father and his people, \"What are these images, to which ye are (so assiduously) devoted", romanUrdu: "Yaad karo woh mauqa ke usne apne baap aur apni qaum se kaha tha ke “yeh muratein (images) kaisi hain jinke tumlog girwida (devoted) ho rahey ho?”" },
    { number: 53, arabic: "قَالُوا۟ وَجَدْنَآ ءَابَآءَنَا لَهَا عَٰبِدِينَ", transliteration: "Qaloo wajadna abaana laha AAabideena", transliterationB: "Qaaloo wajadnaaa aabaaa'anaa lahaa 'aabideen", english: "They said, \"We found our fathers worshipping them", romanUrdu: "Unhon ne jawab diya “humne apne baap dada ko inki ibadat karte paya hai”" },
    { number: 54, arabic: "قَالَ لَقَدْ كُنتُمْ أَنتُمْ وَءَابَآؤُكُمْ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Qala laqad kuntum antum waabaokum fee dalalin mubeenin", transliterationB: "Qaala laqad kuntum antum wa aabaaa'ukum fee dalaalim mubeen", english: "He said, \"Indeed ye have been in manifest error - ye and your fathers", romanUrdu: "Usne kaha “tum bhi gumraah ho aur tumhare baap dada bhi sareeh gumaraahi mein paday huey thay?”" },
    { number: 55, arabic: "قَالُوٓا۟ أَجِئْتَنَا بِٱلْحَقِّ أَمْ أَنتَ مِنَ ٱللَّٰعِبِينَ", transliteration: "Qaloo ajitana bialhaqqi am anta mina allaAAibeena", transliterationB: "Qaalooo aji'tanaa bil haqqi am anta minal laa'ibeen", english: "They said, \"Have you brought us the Truth, or are you one of those who jest", romanUrdu: "Unhon ne kaha “kya tu hamare samne apne asli khayalaat pesh kar raha hai ya mazaaq karta hai?”" },
    { number: 56, arabic: "قَالَ بَل رَّبُّكُمْ رَبُّ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ٱلَّذِى فَطَرَهُنَّ وَأَنَا۠ عَلَىٰ ذَٰلِكُم مِّنَ ٱلشَّٰهِدِينَ", transliteration: "Qala bal rabbukum rabbu alssamawati waalardi allathee fatarahunna waana AAala thalikum mina alshshahideena", transliterationB: "Qaala bar Rabbukum Rabbus samaawaati wal ardil lazee fatarahunna wa ana 'alaa zaalikum minash shaahideen", english: "He said, \"Nay, your Lord is the Lord of the heavens and the earth, He Who created them (from nothing): and I am a witness to this (Truth)", romanUrdu: "Usne jawab diya “nahin, balke fil waqey tumhara Rubb wahi hai jo zameen aur aasmano ka Rubb aur unka paida karne wala hai, ispar main tumhare samne gawahi deta hoon" },
    { number: 57, arabic: "وَتَٱللَّهِ لَأَكِيدَنَّ أَصْنَٰمَكُم بَعْدَ أَن تُوَلُّوا۟ مُدْبِرِينَ", transliteration: "WataAllahi laakeedanna asnamakum baAAda an tuwalloo mudbireena", transliterationB: "Wa tallaahi la akeedanna asnaamakum ba'da an tuwalloo mudbireen", english: "And by Allah, I have a plan for your idols - after ye go away and turn your backs", romanUrdu: "Aur khuda ki kasam main tumhari gair maujoodgi mein zaroor tumhare buthon (idols/murtiyon) ki khabar lunga”" },
    { number: 58, arabic: "فَجَعَلَهُمْ جُذَٰذًا إِلَّا كَبِيرًۭا لَّهُمْ لَعَلَّهُمْ إِلَيْهِ يَرْجِعُونَ", transliteration: "FajaAAalahum juthathan illa kabeeran lahum laAAallahum ilayhi yarjiAAoona", transliterationB: "Faja'alahum juzaazan illaa kabeeral lahum la'allahum ilaihi yarji'oon", english: "So he broke them to pieces, (all) but the biggest of them, that they might turn (and address themselves) to it", romanUrdu: "Chunanchey usne unko tukde tukde kardiya aur sirf unke baday ko chodh diya taa-ke shayad woh iski taraf rujoo karein" },
    { number: 59, arabic: "قَالُوا۟ مَن فَعَلَ هَٰذَا بِـَٔالِهَتِنَآ إِنَّهُۥ لَمِنَ ٱلظَّٰلِمِينَ", transliteration: "Qaloo man faAAala hatha bialihatina innahu lamina alththalimeena", transliterationB: "Qaaloo man fa'ala haazaa bi aalihatinaaa innahoo laminaz zaalimeen", english: "They said, \"Who has done this to our gods? He must indeed be some man of impiety", romanUrdu: "Unhon ne aakar buthon[idols] ka yeh haal dekha to) kehne lagey “hamare khudaon ka yeh haal kisne kardiya? Bada hi koi zalim tha woh”" },
    { number: 60, arabic: "قَالُوا۟ سَمِعْنَا فَتًۭى يَذْكُرُهُمْ يُقَالُ لَهُۥٓ إِبْرَٰهِيمُ", transliteration: "Qaloo samiAAna fatan yathkuruhum yuqalu lahu ibraheemu", transliterationB: "Qaaloo sami'naa fatany yazkuruhum yuqaalu lahooo Ibraaheem", english: "They said, \"We heard a youth talk of them: He is called Abraham", romanUrdu: "(baaz log) boley “ humne ek nawjawan ko inka zikr karte suna tha jiska naam Ibrahim hai”" },
    { number: 61, arabic: "قَالُوا۟ فَأْتُوا۟ بِهِۦ عَلَىٰٓ أَعْيُنِ ٱلنَّاسِ لَعَلَّهُمْ يَشْهَدُونَ", transliteration: "Qaloo fatoo bihi AAala aAAyuni alnnasi laAAallahum yashhadoona", transliterationB: "Qaaloo faatoo bihee 'alaaa a'yunin naasi la'allahum yash hadoon", english: "They said, \"Then bring him before the eyes of the people, that they may bear witness", romanUrdu: "Unhon ne kaha “ to pakad lao usey sabke samne taa-ke log dekh lein (uski kaisi khabar li jati hai)”" },
    { number: 62, arabic: "قَالُوٓا۟ ءَأَنتَ فَعَلْتَ هَٰذَا بِـَٔالِهَتِنَا يَٰٓإِبْرَٰهِيمُ", transliteration: "Qaloo aanta faAAalta hatha bialihatina ya ibraheemu", transliterationB: "Qaalooo 'a-anta fa'alta haazaa bi aalihatinaa yaaa Ibraaheem", english: "They said, \"Art thou the one that did this with our gods, O Abraham", romanUrdu: "(Ibrahim ke aane par) unhon ne pucha “kyun Ibrahim, tu nay hamare khudaon ke saath yeh harakat ki hai" },
    { number: 63, arabic: "قَالَ بَلْ فَعَلَهُۥ كَبِيرُهُمْ هَٰذَا فَسْـَٔلُوهُمْ إِن كَانُوا۟ يَنطِقُونَ", transliteration: "Qala bal faAAalahu kabeeruhum hatha faisaloohum in kanoo yantiqoona", transliterationB: "Qaala bal fa'alahoo kabeeruhum haazaa fas'aloohum in kaanoo yantiqoon", english: "He said: \"Nay, this was done by - this is their biggest one! ask them, if they can speak intelligently", romanUrdu: "Usne jawab diya “balke yeh sab kuch inke is sardar ne kiya hai, inhi se pooch lo agar yeh bolte hon”" },
    { number: 64, arabic: "فَرَجَعُوٓا۟ إِلَىٰٓ أَنفُسِهِمْ فَقَالُوٓا۟ إِنَّكُمْ أَنتُمُ ٱلظَّٰلِمُونَ", transliteration: "FarajaAAoo ila anfusihim faqaloo innakum antumu alththalimoona", transliterationB: "Faraja'ooo ilaaa anfusihim faqaalooo innakum antumuz zaalimoon", english: "So they turned to themselves and said, \"Surely ye are the ones in the wrong", romanUrdu: "Yeh sunkar woh log apne zameer ki taraf palte aur (apne dilon mein) kehne lagey “waqayi tum khud hi zalim ho”" },
    { number: 65, arabic: "ثُمَّ نُكِسُوا۟ عَلَىٰ رُءُوسِهِمْ لَقَدْ عَلِمْتَ مَا هَٰٓؤُلَآءِ يَنطِقُونَ", transliteration: "Thumma nukisoo AAala ruoosihim laqad AAalimta ma haolai yantiqoona", transliterationB: "Summa nukisoo 'alaa ru'oosihim laqad 'alimta maa haaa'ulaaa'i yantiqoon", english: "Then were they confounded with shame: (they said), \"Thou knowest full well that these (idols) do not speak", romanUrdu: "Magar phir unki math palat gayi(minds became perverse) aur boley “ tu jaanta hai ke yeh bolte nahin hain”" },
    { number: 66, arabic: "قَالَ أَفَتَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُكُمْ شَيْـًۭٔا وَلَا يَضُرُّكُمْ", transliteration: "Qala afataAAbudoona min dooni Allahi ma la yanfaAAukum shayan wala yadurrukum", transliterationB: "Qaala afata'budoona min doonil laahi maa laa yanfa'ukum shai'anw wa laa yadurrukum", english: "(Abraham) said, \"Do ye then worship, besides Allah, things that can neither be of any good to you nor do you harm", romanUrdu: "Ibrahim ne kaha “phir kya tum Allah ko chodh kar un cheezon ko poojh rahey ho jo na tumhein nafaa pahunchane par qadir hain na nuqsan" },
    { number: 67, arabic: "أُفٍّۢ لَّكُمْ وَلِمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ ۖ أَفَلَا تَعْقِلُونَ", transliteration: "Offin lakum walima taAAbudoona min dooni Allahi afala taAAqiloona", transliterationB: "Uffil lakum wa limaa ta'budoona min doonil laah; afalaa ta'qiloon", english: "Fie upon you, and upon the things that ye worship besides Allah! Have ye no sense", romanUrdu: "Tuff (Fie) hai tumpar aur tumhare in maboodon par jinki tum Allah ko chodh kar pooja kar rahey ho, kya tum kuch bhi aqal nahin rakhte?”" },
    { number: 68, arabic: "قَالُوا۟ حَرِّقُوهُ وَٱنصُرُوٓا۟ ءَالِهَتَكُمْ إِن كُنتُمْ فَٰعِلِينَ", transliteration: "Qaloo harriqoohu waonsuroo alihatakum in kuntum faAAileena", transliterationB: "Qaaloo harriqooho wansurooo aalihatakum in kuntum faa'ileen", english: "They said, \"Burn him and protect your gods, If ye do (anything at all)", romanUrdu: "Unhon ne kaha “jala daalo isko aur himayat karo apne khudaon ki agar tumhein kuch karna hai”" },
    { number: 69, arabic: "قُلْنَا يَٰنَارُ كُونِى بَرْدًۭا وَسَلَٰمًا عَلَىٰٓ إِبْرَٰهِيمَ", transliteration: "Qulna ya naru koonee bardan wasalaman AAala ibraheema", transliterationB: "Qulnaa yaa naaru koonee bardanw wa salaaman 'alaaa Ibraaheem", english: "We said, \"O Fire! be thou cool, and (a means of) safety for Abraham", romanUrdu: "Humne kaha “Aey aag, thandi ho jaa aur salamati ban jaa Ibrahim par”" },
    { number: 70, arabic: "وَأَرَادُوا۟ بِهِۦ كَيْدًۭا فَجَعَلْنَٰهُمُ ٱلْأَخْسَرِينَ", transliteration: "Waaradoo bihi kaydan fajaAAalnahumu alakhsareena", transliterationB: "Wa araadoo bihee kaidan faja'alnaahumul akhsareen", english: "Then they sought a stratagem against him: but We made them the ones that lost most", romanUrdu: "Woh chahte thay ke Ibrahim ke saath burayi karein magar humne unko buri tarah nakaam kardiya" },
    { number: 71, arabic: "وَنَجَّيْنَٰهُ وَلُوطًا إِلَى ٱلْأَرْضِ ٱلَّتِى بَٰرَكْنَا فِيهَا لِلْعَٰلَمِينَ", transliteration: "Wanajjaynahu walootan ila alardi allatee barakna feeha lilAAalameena", transliterationB: "Wa najjainaahu wa Lootan ilal ardil latee baaraknaa feehaa lil 'aalameen", english: "But We delivered him and (his nephew) Lut (and directed them) to the land which We have blessed for the nations", romanUrdu: "Aur hum usey aur Lut ko bacha kar us sar-zameen ki taraf nikal le gaye jismein humne duniya walon ke liye barkatein rakkhi hain" },
    { number: 72, arabic: "وَوَهَبْنَا لَهُۥٓ إِسْحَٰقَ وَيَعْقُوبَ نَافِلَةًۭ ۖ وَكُلًّۭا جَعَلْنَا صَٰلِحِينَ", transliteration: "Wawahabna lahu ishaqa wayaAAqooba nafilatan wakullan jaAAalna saliheena", transliterationB: "Wa wahabnaa lahooo Ishaaq; wa Ya'qooba naafilah; wa kullan ja'alnaa saaliheen", english: "And We bestowed on him Isaac and, as an additional gift, (a grandson), Jacob, and We made righteous men of every one (of them)", romanUrdu: "Aur humne usey Ishaq ata kiya aur Yakoob uspar mazeed, aur har ek ko saleh (righteous) banaya" },
    { number: 73, arabic: "وَجَعَلْنَٰهُمْ أَئِمَّةًۭ يَهْدُونَ بِأَمْرِنَا وَأَوْحَيْنَآ إِلَيْهِمْ فِعْلَ ٱلْخَيْرَٰتِ وَإِقَامَ ٱلصَّلَوٰةِ وَإِيتَآءَ ٱلزَّكَوٰةِ ۖ وَكَانُوا۟ لَنَا عَٰبِدِينَ", transliteration: "WajaAAalnahum aimmatan yahdoona biamrina waawhayna ilayhim fiAAla alkhayrati waiqama alssalati waeetaa alzzakati wakanoo lana AAabideena", transliterationB: "Wa ja'alnaahum a'immatany yahdoona bi amrinaa wa awhainaaa ilaihim fi'lal khairaati wa iqaamas Salaati wa eetaaa'az Zakaati wa kaanoo lanaa 'aabideen", english: "And We made them leaders, guiding (men) by Our Command, and We sent them inspiration to do good deeds, to establish regular prayers, and to practise regular charity; and they constantly served Us (and Us only)", romanUrdu: "Aur humne unko imam bana diya jo hamare hukum se rehnumayi karte thay aur humne unhein wahee (revelation) ke zariye neik kaamon ki aur namaz qayam karne ki aur zakat dene ki hidayat ki, aur woh hamare ibadat guzaar thay" },
    { number: 74, arabic: "وَلُوطًا ءَاتَيْنَٰهُ حُكْمًۭا وَعِلْمًۭا وَنَجَّيْنَٰهُ مِنَ ٱلْقَرْيَةِ ٱلَّتِى كَانَت تَّعْمَلُ ٱلْخَبَٰٓئِثَ ۗ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍۢ فَٰسِقِينَ", transliteration: "Walootan ataynahu hukman waAAilman wanajjaynahu mina alqaryati allatee kanat taAAmalu alkhabaitha innahum kanoo qawma sawin fasiqeena", transliterationB: "Wa Lootan aatainaahu hukmanw wa 'ilmanw wa najjainaahu minal qaryatil latee kaanat ta'malul khabaaa'is; innahum kaanoo qawma saw'in faasiqeen", english: "And to Lut, too, We gave Judgment and Knowledge, and We saved him from the town which practised abominations: truly they were a people given to Evil, a rebellious people", romanUrdu: "Aur Lut ko humne hukum aur ilm baksha aur usey us basti se bacha kar nikal diya jo badkariyan karti thi. Dar haqeeqat woh badi hi buri, fasiq qaum thi" },
    { number: 75, arabic: "وَأَدْخَلْنَٰهُ فِى رَحْمَتِنَآ ۖ إِنَّهُۥ مِنَ ٱلصَّٰلِحِينَ", transliteration: "Waadkhalnahu fee rahmatina innahu mina alssaliheena", transliterationB: "Wa adkhalnaahu fee rahmatinaa innahoo minas saalihee", english: "And We admitted him to Our Mercy: for he was one of the Righteous", romanUrdu: "Aur Lut ko humne apni rehmat mein dakhil kiya, woh saleh logon mein se tha" },
    { number: 76, arabic: "وَنُوحًا إِذْ نَادَىٰ مِن قَبْلُ فَٱسْتَجَبْنَا لَهُۥ فَنَجَّيْنَٰهُ وَأَهْلَهُۥ مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ", transliteration: "Wanoohan ith nada min qablu faistajabna lahu fanajjaynahu waahlahu mina alkarbi alAAatheemi", transliterationB: "Wa noohan iz naadaa min qablu fastajabnaa lahoo fanajjainaahu wa ahlahoo minal karbil 'azeem", english: "(Remember) Noah, when he cried (to Us) aforetime: We listened to his (prayer) and delivered him and his family from great distress", romanUrdu: "Aur yahi niyamat humne Nooh ko di, yaad karo jabke in sab se pehle usne humein pukara tha, humne uski dua qabool ki aur usey aur uske ghar walon ko karb-e-azeem (great calamity) se najaat di" },
    { number: 77, arabic: "وَنَصَرْنَٰهُ مِنَ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍۢ فَأَغْرَقْنَٰهُمْ أَجْمَعِينَ", transliteration: "Wanasarnahu mina alqawmi allatheena kaththaboo biayatina innahum kanoo qawma sawin faaghraqnahum ajmaAAeena", transliterationB: "Wa nasarnaahu minal qawmil lazeena kazzaboo bi Aayaatinaa; innahum kkaanoo qawma saw'in fa-aghraq naahum ajma'een", english: "We helped him against people who rejected Our Signs: truly they were a people given to Evil: so We drowned them (in the Flood) all together", romanUrdu: "Aur us qaum ke muqaable mein uski madad ki jisne hamari aayat ko jhutla diya tha. Woh baday burey log thay, pas humne un sabko garq (drown) kardiya" },
    { number: 78, arabic: "وَدَاوُۥدَ وَسُلَيْمَٰنَ إِذْ يَحْكُمَانِ فِى ٱلْحَرْثِ إِذْ نَفَشَتْ فِيهِ غَنَمُ ٱلْقَوْمِ وَكُنَّا لِحُكْمِهِمْ شَٰهِدِينَ", transliteration: "Wadawooda wasulaymana ith yahkumani fee alharthi ith nafashat feehi ghanamu alqawmi wakunna lihukmihim shahideena", transliterationB: "Wa Daawooda wa Sulaimaana iz yahkumaani fil harsi iz nafashat feehi ghanamul qawmi wa kunnaa lihukmihim shaahideen", english: "And remember David and Solomon, when they gave judgment in the matter of the field into which the sheep of certain people had strayed by night: We did witness their judgment", romanUrdu: "Aur isi niyamat se humne Dawood aur Suleiman ko sarfaraz kiya. Yaad karo woh mauqa jabke woh dono ek khet (field) ke muqaddame mein faisla kar rahey thay jismein raat ke waqt dusre logon ki bakriyan(goats) phayl gayi thin (strayed at night),aur hum unki adalat khud dekh rahey thay" },
    { number: 79, arabic: "فَفَهَّمْنَٰهَا سُلَيْمَٰنَ ۚ وَكُلًّا ءَاتَيْنَا حُكْمًۭا وَعِلْمًۭا ۚ وَسَخَّرْنَا مَعَ دَاوُۥدَ ٱلْجِبَالَ يُسَبِّحْنَ وَٱلطَّيْرَ ۚ وَكُنَّا فَٰعِلِينَ", transliteration: "Fafahhamnaha sulaymana wakullan atayna hukman waAAilman wasakhkharna maAAa dawooda aljibala yusabbihna waalttayra wakunna faAAileena", transliterationB: "Fafahhamnaahaa sulaimaan; wa kullan aatainaa hukmanw wa'ilmanw wa sakh kharnaa ma'a Daawoodal jibaala yusabbihna wattayr; wa kunnaa faa'ileen", english: "To Solomon We inspired the (right) understanding of the matter: to each (of them) We gave Judgment and Knowledge; it was Our power that made the hills and the birds celebrate Our praises, with David: it was We Who did (all these things)", romanUrdu: "Us waqt humne sahih faisla Sulaiman ko samjha diya, halaanke hukum aur ilm humne dono hi ko ata kiya tha. Dawood ke saath humne pahadon aur parindon ko musakkhar kardiya tha jo tasbeeh karte thay, is fail (kaam) ke karne waley hum hi thay" },
    { number: 80, arabic: "وَعَلَّمْنَٰهُ صَنْعَةَ لَبُوسٍۢ لَّكُمْ لِتُحْصِنَكُم مِّنۢ بَأْسِكُمْ ۖ فَهَلْ أَنتُمْ شَٰكِرُونَ", transliteration: "WaAAallamnahu sanAAata laboosin lakum lituhsinakum min basikum fahal antum shakiroona", transliterationB: "Wa 'allamanaahu san'ata laboosil lakum lituhsinakum mim baasikum fahal antum shaakiroon", english: "It was We Who taught him the making of coats of mail for your benefit, to guard you from each other's violence: will ye then be grateful", romanUrdu: "Aur humne usko tumhare faiyde ke liye zira (coats of armor) banane ki sanat (craft) sikha di thi, taa-ke tumko ek dusre ki maar se bachaye, phir kya tum shukar guzar ho" },
    { number: 81, arabic: "وَلِسُلَيْمَٰنَ ٱلرِّيحَ عَاصِفَةًۭ تَجْرِى بِأَمْرِهِۦٓ إِلَى ٱلْأَرْضِ ٱلَّتِى بَٰرَكْنَا فِيهَا ۚ وَكُنَّا بِكُلِّ شَىْءٍ عَٰلِمِينَ", transliteration: "Walisulaymana alrreeha AAasifatan tajree biamrihi ila alardi allatee barakna feeha wakunna bikulli shayin AAalimeena", transliterationB: "Wa li Sulaimaanar reeha 'aasifatan tajree bi amriheee ilal ardil latee baaraknaa feehaa; wa kunnaa bikulli shai'in 'aalimeen", english: "(It was Our power that made) the violent (unruly) wind flow (tamely) for Solomon, to his order, to the land which We had blessed: for We do know all things", romanUrdu: "Aur Sulaiman ke liye humne teiz hawa ko musakkhar kardiya tha jo uske hukum se us sar-zameen ki taraf chalti thi jismein humne barkatein rakkhi hain. Hum har cheez ka ilm rakhne waley thay" },
    { number: 82, arabic: "وَمِنَ ٱلشَّيَٰطِينِ مَن يَغُوصُونَ لَهُۥ وَيَعْمَلُونَ عَمَلًۭا دُونَ ذَٰلِكَ ۖ وَكُنَّا لَهُمْ حَٰفِظِينَ", transliteration: "Wamina alshshayateeni man yaghoosoona lahu wayaAAmaloona AAamalan doona thalika wakunna lahum hafitheena", transliterationB: "Wa minash Shayaateeni mai yaghoosoona lahoo wa ya'maloona 'amalan doona zaalika wa kunna lahum baafizeen", english: "And of the evil ones, were some who dived for him, and did other work besides; and it was We Who guarded them", romanUrdu: "Aur shayateen mein se humne aisey bahutson (many) ko uska tabey bana diya tha jo uske liye ghotey (diving) lagate aur iske siwa dusre kaam karte thay, in sab ke nigraan hum hi thay" },
    { number: 83, arabic: "۞ وَأَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلضُّرُّ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ", transliteration: "Waayyooba ith nada rabbahu annee massaniya alddurru waanta arhamu alrrahimeena", transliterationB: "Wa Ayyooba iz naadaa Rabbahooo annee massaniyad durru wa Anta arhamur raahimeen", english: "And (remember) Job, when He cried to his Lord, \"Truly distress has seized me, but Thou art the Most Merciful of those that are merciful", romanUrdu: "Aur yahi (hosh-mandi aur hukum o ilm ki niyamat) humne Ayub ko di thi. Yaad karo jabke usne apne Rubb ko pukara ke “mujhey bimaari lag gayi hai aur tu arham ur rahimeen (sab se badhkar reham karne wala) hai.”" },
    { number: 84, arabic: "فَٱسْتَجَبْنَا لَهُۥ فَكَشَفْنَا مَا بِهِۦ مِن ضُرٍّۢ ۖ وَءَاتَيْنَٰهُ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةًۭ مِّنْ عِندِنَا وَذِكْرَىٰ لِلْعَٰبِدِينَ", transliteration: "Faistajabna lahu fakashafna ma bihi min durrin waataynahu ahlahu wamithlahum maAAahum rahmatan min AAindina wathikra lilAAabideena", transliterationB: "Fastajabnaa lahoo fakashaf naa maa bihee min durrinw wa aatainaahu ahlahoo wa mislahum ma'ahum rahmatam min 'indinaa wa zikraa lil'aabideen", english: "So We listened to him: We removed the distress that was on him, and We restored his people to him, and doubled their number,- as a Grace from Ourselves, and a thing for commemoration, for all who serve Us", romanUrdu: "Humne uski dua qabool ki aur jo takleef usey thi usko door kardiya, aur sirf uske ehl-o-ayal hi usko nahin diye balke unke saath utne hi aur bhi diye, apni khaas rehmat ke taur par, aur isliye ke yeh ek sabaq ho ibadat guzaaron keliye" },
    { number: 85, arabic: "وَإِسْمَٰعِيلَ وَإِدْرِيسَ وَذَا ٱلْكِفْلِ ۖ كُلٌّۭ مِّنَ ٱلصَّٰبِرِينَ", transliteration: "WaismaAAeela waidreesa watha alkifli kullun mina alssabireena", transliterationB: "Wa Ismaa'eela wa Idreesa wa Zal Kifli kullum minas saabireen", english: "And (remember) Isma'il, Idris, and Zul-kifl, all (men) of constancy and patience", romanUrdu: "Aur yahi niyamat Ismail aur Idris(Enoch) aur Dhul-Kifl (Isaiah) ko di, ke yeh sab saabir log (practised fortitude) thay" },
    { number: 86, arabic: "وَأَدْخَلْنَٰهُمْ فِى رَحْمَتِنَآ ۖ إِنَّهُم مِّنَ ٱلصَّٰلِحِينَ", transliteration: "Waadkhalnahum fee rahmatina innahum mina alssaliheena", transliterationB: "Wa adkhalnaahum fee rahmatinaa innahum minas saaliheen", english: "We admitted them to Our mercy: for they were of the righteous ones", romanUrdu: "Aur unko humne apni rehmat mein dakhil kiya ke woh salihon (righteous people) mein se thay" },
    { number: 87, arabic: "وَذَا ٱلنُّونِ إِذ ذَّهَبَ مُغَٰضِبًۭا فَظَنَّ أَن لَّن نَّقْدِرَ عَلَيْهِ فَنَادَىٰ فِى ٱلظُّلُمَٰتِ أَن لَّآ إِلَٰهَ إِلَّآ أَنتَ سُبْحَٰنَكَ إِنِّى كُنتُ مِنَ ٱلظَّٰلِمِينَ", transliteration: "Watha alnnooni ith thahaba mughadiban fathanna an lan naqdira AAalayhi fanada fee alththulumati an la ilaha illa anta subhanaka innee kuntu mina alththalimeena", transliterationB: "Wa Zan Nooni iz zahaba mughaadiban fazaanna al lan naqdira 'alaihi fanaanna al lan naqdira 'alaihi fanaadaa fiz zulumaati al laaa ilaaha illaaa Anta Subhaanaka innee kuntu minaz zaalimeen", english: "And remember Zun-nun, when he departed in wrath: He imagined that We had no power over him! But he cried through the deptHs of darkness, \"There is no god but thou: glory to thee: I was indeed wrong", romanUrdu: "Aur machli waley(yunus) ko bhi humne nawaza, yaad karo jabke woh bigad kar chala gaya tha aur samjha tha ke hum uspar giraft na karenge. Aakhir ko usne tareekiyon(darkness) mein pukara “nahin hai koi khuda magar tu, paak hai teri zaat, beshak maine kasoor kiya”" },
    { number: 88, arabic: "فَٱسْتَجَبْنَا لَهُۥ وَنَجَّيْنَٰهُ مِنَ ٱلْغَمِّ ۚ وَكَذَٰلِكَ نُۨجِى ٱلْمُؤْمِنِينَ", transliteration: "Faistajabna lahu wanajjaynahu mina alghammi wakathalika nunjee almumineena", transliterationB: "Fastajabnaa lahoo wa najjainaahu minal ghamm; wa kazaalika nunjil mu'mineen", english: "So We listened to him: and delivered him from distress: and thus do We deliver those who have faith", romanUrdu: "Tab humne uski dua qabool ki aur ghum se usko najaat bakshi, aur isi taraah hum momino ko bacha liya karte hain" },
    { number: 89, arabic: "وَزَكَرِيَّآ إِذْ نَادَىٰ رَبَّهُۥ رَبِّ لَا تَذَرْنِى فَرْدًۭا وَأَنتَ خَيْرُ ٱلْوَٰرِثِينَ", transliteration: "Wazakariyya ith nada rabbahu rabbi la tatharnee fardan waanta khayru alwaritheena", transliterationB: "Wa Zakariyyaaa iz naadaa Rabbahoo Rabbi laa tazarnee fardanw wa Anta khairul waariseen", english: "And (remember) Zakariya, when he cried to his Lord: \"O my Lord! leave me not without offspring, though thou art the best of inheritors", romanUrdu: "Aur zakariya ko, jabke usne apne Rubb ko pukara ke “aey parwardigar, mujhey akela na chodh, aur behtareen waris to tu hi hai”" },
    { number: 90, arabic: "فَٱسْتَجَبْنَا لَهُۥ وَوَهَبْنَا لَهُۥ يَحْيَىٰ وَأَصْلَحْنَا لَهُۥ زَوْجَهُۥٓ ۚ إِنَّهُمْ كَانُوا۟ يُسَٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَيَدْعُونَنَا رَغَبًۭا وَرَهَبًۭا ۖ وَكَانُوا۟ لَنَا خَٰشِعِينَ", transliteration: "Faistajabna lahu wawahabna lahu yahya waaslahna lahu zawjahu innahum kanoo yusariAAoona fee alkhayrati wayadAAoonana raghaban warahaban wakanoo lana khashiAAeena", transliterationB: "Fastajabnaa lahoo wa wahabnaa lahoo Yahyaa Wa aslahnaa lahoo zawjah; innahum kaanoo yusaari'oona fil khairaati wa yad'oonanaa raghabanw wa rahabaa; wa kaanoo lanaa khaashi'een", english: "So We listened to him: and We granted him Yahya: We cured his wife's (Barrenness) for him. These (three) were ever quick in emulation in good works; they used to call on Us with love and reverence, and humble themselves before Us", romanUrdu: "Pas humne uski dua qabool ki aur usey Yahya ata kiya aur uski biwi ko uske liye durust kardiya, yeh log neki ke kaamon mein daud-dhoop karte thay aur humein ragbat (with love) aur khauf ke saath pukarte thay, aur hamare aagey jhuke huey thay" },
    { number: 91, arabic: "وَٱلَّتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهَا مِن رُّوحِنَا وَجَعَلْنَٰهَا وَٱبْنَهَآ ءَايَةًۭ لِّلْعَٰلَمِينَ", transliteration: "Waallatee ahsanat farjaha fanafakhna feeha min roohina wajaAAalnaha waibnaha ayatan lilAAalameena", transliterationB: "Wallateee ahsanat farjahaa fanafakhnaa feehaa mir roohinaa wa ja'alnaahaa wabnahaaa Aayatal lil'aalameen", english: "And (remember) her who guarded her chastity: We breathed into her of Our spirit, and We made her and her son a sign for all peoples", romanUrdu: "Aur woh khaatun jisne apni ismat (chastity) ki hifazat ki thi, humne uske andar apni rooh se phoonka aur usey aur uske bete ko duniya bhar ke liye nishani bana diya" },
    { number: 92, arabic: "إِنَّ هَٰذِهِۦٓ أُمَّتُكُمْ أُمَّةًۭ وَٰحِدَةًۭ وَأَنَا۠ رَبُّكُمْ فَٱعْبُدُونِ", transliteration: "Inna hathihi ommatukum ommatan wahidatan waana rabbukum faoAAbudooni", transliterationB: "Inna haaziheee ummatukum ummatanw waahidatanw wa Ana Rabbukum fa'budoon", english: "Verily, this brotherhood of yours is a single brotherhood, and I am your Lord and Cherisher: therefore serve Me (and no other)", romanUrdu: "Yeh tumhari ummat haqeeqat mein ek hi ummat hai aur main tumhara Rubb hoon, pas tum meri ibadat karo" },
    { number: 93, arabic: "وَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ ۖ كُلٌّ إِلَيْنَا رَٰجِعُونَ", transliteration: "WataqattaAAoo amrahum baynahum kullun ilayna rajiAAoona", transliterationB: "Wa taqatta'ooo amrahum bainahum kullun ilainaaa raaji'oon", english: "But (later generations) cut off their affair (of unity), one from another: (yet) will they all return to Us", romanUrdu: "Magar (yeh logon ki karastani hai ke) inhon ne aapas mein deen ko tukde tukde kar dala, sabko hamari taraf palatna hai" },
    { number: 94, arabic: "فَمَن يَعْمَلْ مِنَ ٱلصَّٰلِحَٰتِ وَهُوَ مُؤْمِنٌۭ فَلَا كُفْرَانَ لِسَعْيِهِۦ وَإِنَّا لَهُۥ كَٰتِبُونَ", transliteration: "Faman yaAAmal mina alssalihati wahuwa muminun fala kufrana lisaAAyihi wainna lahu katiboona", transliterationB: "Famai ya'mal minas saalihaati wa huwa mu'minun falaa kufraana lisa'yihee wa innaa lahoo kaatiboon", english: "Whoever works any act of righteousness and has faith,- His endeavour will not be rejected: We shall record it in his favour", romanUrdu: "Phir jo neik amal karega, is haal mein ke woh momin ho, to uske kaam ki na-qadri na hogi, aur usey hum likh rahey hain" },
    { number: 95, arabic: "وَحَرَٰمٌ عَلَىٰ قَرْيَةٍ أَهْلَكْنَٰهَآ أَنَّهُمْ لَا يَرْجِعُونَ", transliteration: "Waharamun AAala qaryatin ahlaknaha annahum la yarjiAAoona", transliterationB: "Wa haraamun 'alaa qaryatin ahlaknaahaaa annahum laa yarji'oon", english: "But there is a ban on any population which We have destroyed: that they shall not return", romanUrdu: "Aur mumkin nahin hai ke jis basti ko humne halaak kardiya ho woh phir palat sakey" },
    { number: 96, arabic: "حَتَّىٰٓ إِذَا فُتِحَتْ يَأْجُوجُ وَمَأْجُوجُ وَهُم مِّن كُلِّ حَدَبٍۢ يَنسِلُونَ", transliteration: "Hatta itha futihat yajooju wamajooju wahum min kulli hadabin yansiloona", transliterationB: "Hattaaa izaa futihat Yaajooju wa Maajooju wa hum min kulli hadabiny yansiloon", english: "Until the Gog and Magog (people) are let through (their barrier), and they swiftly swarm from every hill", romanUrdu: "Yahaan tak ke jab yajooj majooj khol diye jayenge aur har bulandi se woh nikal padenge" },
    { number: 97, arabic: "وَٱقْتَرَبَ ٱلْوَعْدُ ٱلْحَقُّ فَإِذَا هِىَ شَٰخِصَةٌ أَبْصَٰرُ ٱلَّذِينَ كَفَرُوا۟ يَٰوَيْلَنَا قَدْ كُنَّا فِى غَفْلَةٍۢ مِّنْ هَٰذَا بَلْ كُنَّا ظَٰلِمِينَ", transliteration: "Waiqtaraba alwaAAdu alhaqqu faitha hiya shakhisatun absaru allatheena kafaroo ya waylana qad kunna fee ghaflatin min hatha bal kunna thalimeena", transliterationB: "Waqtarabal wa'dul haqqu fa-izaa hiya shaakhisatun absaarul lazeena kafaroo yaawailanaa qad kunna fee ghaflatim min haaza bal kunnaa zaalimeen", english: "Then will the true promise draw nigh (of fulfilment): then behold! the eyes of the Unbelievers will fixedly stare in horror: \"Ah! Woe to us! we were indeed heedless of this; nay, we truly did wrong", romanUrdu: "Aur wada bar haqq ke poora hone ka waqt qareeb aa lagega to yakayak un logon ke deedhey phatey ke phatey reh jayenge (fixedly stare in horror), jinhon ne kufr kiya tha. Kahenge “haaye hamari kambakhti, hum is cheez ki taraf se gaflat mein padey huey thay, balke hum khatakaar thay.”" },
    { number: 98, arabic: "إِنَّكُمْ وَمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ حَصَبُ جَهَنَّمَ أَنتُمْ لَهَا وَٰرِدُونَ", transliteration: "Innakum wama taAAbudoona min dooni Allahi hasabu jahannama antum laha waridoona", transliterationB: "Innakum wa maa ta'budoona min doonil laahi hasabu Jahannama antum lahaa waaridoon", english: "Verily ye, (unbelievers), and the (false) gods that ye worship besides Allah, are (but) fuel for Hell! to it will ye (surely) come", romanUrdu: "Beshak tum aur tumhare woh mabood jinhein tum poojhte ho, jahannum ka indhan (fuel) hain, wahin tumko jana hai" },
    { number: 99, arabic: "لَوْ كَانَ هَٰٓؤُلَآءِ ءَالِهَةًۭ مَّا وَرَدُوهَا ۖ وَكُلٌّۭ فِيهَا خَٰلِدُونَ", transliteration: "Law kana haolai alihatan ma waradooha wakullun feeha khalidoona", transliterationB: "Law kaana haaa'ulaaa'i aalihatam maa waradoohaa wa kullun feehaa khaalidoon", english: "If these had been gods, they would not have got there! but each one will abide therein", romanUrdu: "Agar yeh waqayi khuda hotey to wahan na jatey, ab sabko hamesha usi mein rehna hai.”" },
    { number: 100, arabic: "لَهُمْ فِيهَا زَفِيرٌۭ وَهُمْ فِيهَا لَا يَسْمَعُونَ", transliteration: "Lahum feeha zafeerun wahum feeha la yasmaAAoona", transliterationB: "Lahum feehaa zafeerunw wa hum feehaa laa yasma'oon", english: "There, sobbing will be their lot, nor will they there hear (aught else)", romanUrdu: "Wahaan woh phunkare maarenge (groan/roar) aur haal yeh hoga ke usmein kaan padi aawaaz na sunayi degi" },
    { number: 101, arabic: "إِنَّ ٱلَّذِينَ سَبَقَتْ لَهُم مِّنَّا ٱلْحُسْنَىٰٓ أُو۟لَٰٓئِكَ عَنْهَا مُبْعَدُونَ", transliteration: "Inna allatheena sabaqat lahum minna alhusna olaika AAanha mubAAadoona", transliterationB: "Innal lazeena sabaqat lahum minnal husnaaa ulaaa'ika 'anhaa mub'adoon", english: "Those for whom the good (record) from Us has gone before, will be removed far therefrom", romanUrdu: "Rahey woh log jinke liye hamari taraf se bhalayi ka pehle hi faisla ho chuka hoga, to woh yaqeenan ussey door rakkhey jayenge" },
    { number: 102, arabic: "لَا يَسْمَعُونَ حَسِيسَهَا ۖ وَهُمْ فِى مَا ٱشْتَهَتْ أَنفُسُهُمْ خَٰلِدُونَ", transliteration: "La yasmaAAoona haseesaha wahum fee ma ishtahat anfusuhum khalidoona", transliterationB: "Laa yasma'oona hasee sahaa wa hum fee mash tahat anfusuhum khaalidoon", english: "Not the slightest sound will they hear of Hell: what their souls desired, in that will they dwell", romanUrdu: "Uski sarsarahat tak na sunenge aur woh hamesha hamesha apni mann bhati cheezon ke darmiyan rahenge" },
    { number: 103, arabic: "لَا يَحْزُنُهُمُ ٱلْفَزَعُ ٱلْأَكْبَرُ وَتَتَلَقَّىٰهُمُ ٱلْمَلَٰٓئِكَةُ هَٰذَا يَوْمُكُمُ ٱلَّذِى كُنتُمْ تُوعَدُونَ", transliteration: "La yahzunuhumu alfazaAAu alakbaru watatalaqqahumu almalaikatu hatha yawmukumu allathee kuntum tooAAadoona", transliterationB: "Laa yahzunuhumul faza'ul akbaru wa tatalaq qaahumul malaaa'ikatu haazaa Yawmukumul lazee kuntum too'adoon", english: "The Great Terror will bring them no grief: but the angels will meet them (with mutual greetings): \"This is your Day,- (the Day) that ye were promised", romanUrdu: "Woh intihayi ghabrahat ka waqt unko zara pareshan na karega, aur malaika badh kar unko haathon haath lenge ke “yeh tumhara wahi din hai jiska tumse waada kiya jaata tha”" },
    { number: 104, arabic: "يَوْمَ نَطْوِى ٱلسَّمَآءَ كَطَىِّ ٱلسِّجِلِّ لِلْكُتُبِ ۚ كَمَا بَدَأْنَآ أَوَّلَ خَلْقٍۢ نُّعِيدُهُۥ ۚ وَعْدًا عَلَيْنَآ ۚ إِنَّا كُنَّا فَٰعِلِينَ", transliteration: "Yawma natwee alssamaa katayyi alssijlli lilkutubi kama badana awwala khalqin nuAAeeduhu waAAdan AAalayna inna kunna faAAileena", transliterationB: "Yawma natwis samaaa'a kataiyis sijilli lilkutub; kamaa badaanaa awwala khalqin nu'eeduh; wa'dan 'alainaa; innaa kunna faa'ileen", english: "The Day that We roll up the heavens like a scroll rolled up for books (completed),- even as We produced the first creation, so shall We produce a new one: a promise We have undertaken: truly shall We fulfil it", romanUrdu: "Woh din jabke aasman ko hum yun lapeit kar rakh denge jaise tumar mein awraaq lapeit diye jatey hain (leaves of paper are rolled up in a written scroll) jis tarah pehle humne takhleeq ki ibtida ki thi usi tarah hum phir uska iaada (originate) karenge. Yeh ek wada hai hamare zimme, aur yeh kaam humein bahr-haal karna hai" },
    { number: 105, arabic: "وَلَقَدْ كَتَبْنَا فِى ٱلزَّبُورِ مِنۢ بَعْدِ ٱلذِّكْرِ أَنَّ ٱلْأَرْضَ يَرِثُهَا عِبَادِىَ ٱلصَّٰلِحُونَ", transliteration: "Walaqad katabna fee alzzaboori min baAAdi alththikri anna alarda yarithuha AAibadiya alssalihoona", transliterationB: "Wa laqad katabnaa fiz Zaboori mim ba'diz zikri annal arda yarisuhaa 'ibaadi yas saalihoon", english: "Before this We wrote in the Psalms, after the Message (given to Moses): My servants the righteous, shall inherit the earth", romanUrdu: "Aur Zaboor mein hum naseehat ke baad yeh likh chuke hain ke zameen ke waris hamare neik banday hongey" },
    { number: 106, arabic: "إِنَّ فِى هَٰذَا لَبَلَٰغًۭا لِّقَوْمٍ عَٰبِدِينَ", transliteration: "Inna fee hatha labalaghan liqawmin AAabideena", transliterationB: "Inna fee haaza labalaa ghal liqawmin 'aabideen", english: "Verily in this (Qur'an) is a Message for people who would (truly) worship Allah", romanUrdu: "Is mein ek badi khabar hai ibadat guzar logon ke liye" },
    { number: 107, arabic: "وَمَآ أَرْسَلْنَٰكَ إِلَّا رَحْمَةًۭ لِّلْعَٰلَمِينَ", transliteration: "Wama arsalnaka illa rahmatan lilAAalameena", transliterationB: "Wa maaa arsalnaaka illaa rahmatal lil'aalameen", english: "We sent thee not, but as a Mercy for all creatures", romanUrdu: "(Aey Muhammad), humne jo tumko bheja hai to yeh dar-asal duniya walon ke haqq mein hamari rehmat hai" },
    { number: 108, arabic: "قُلْ إِنَّمَا يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَٰهُكُمْ إِلَٰهٌۭ وَٰحِدٌۭ ۖ فَهَلْ أَنتُم مُّسْلِمُونَ", transliteration: "Qul innama yooha ilayya annama ilahukum ilahun wahidun fahal antum muslimoona", transliterationB: "Qul innamaa yoohaa ilaiya annamaaa ilaahukum illaahunw Waahid, fahal antum muslimoon", english: "Say: \"What has come to me by inspiration is that your Allah is One Allah: will ye therefore bow to His Will (in Islam)", romanUrdu: "Insey kaho, “mere paas jo wahee aati hai woh yeh hai ke tumhara khuda sirf ek khuda hai, phir kya tum sar-e-itaat jhukate ho?”" },
    { number: 109, arabic: "فَإِن تَوَلَّوْا۟ فَقُلْ ءَاذَنتُكُمْ عَلَىٰ سَوَآءٍۢ ۖ وَإِنْ أَدْرِىٓ أَقَرِيبٌ أَم بَعِيدٌۭ مَّا تُوعَدُونَ", transliteration: "Fain tawallaw faqul athantukum AAala sawain wain adree aqareebun am baAAeedun ma tooAAadoona", transliterationB: "Fa in tawallaw faqul aazantukum 'alaa sawaaa'; wa in adreee aqareebun am ba'eedum maa too'adoon", english: "But if they turn back, Say: \"I have proclaimed the Message to you all alike and in truth; but I know not whether that which ye are promised is near or far", romanUrdu: "Agar woh mooh pherein to kehdo “maine alal-ailaan (openly) tumko khabardaar kardiya hai. Ab yeh main nahin jaanta ke woh cheez jiska tumse wada kiya jaa raha hai qareeb hai ya door" },
    { number: 110, arabic: "إِنَّهُۥ يَعْلَمُ ٱلْجَهْرَ مِنَ ٱلْقَوْلِ وَيَعْلَمُ مَا تَكْتُمُونَ", transliteration: "Innahu yaAAlamu aljahra mina alqawli wayaAAlamu ma taktumoona", transliterationB: "Innahoo ya'lamul jahra minal qawli wa ya'lamu maa taktumoon", english: "It is He Who knows what is open in speech and what ye hide (in your hearts)", romanUrdu: "Allah woh baatein bhi jaanta hai jo ba-awaaz buland kahi jati hain aur woh bhi jo tum chupa kar karte ho" },
    { number: 111, arabic: "وَإِنْ أَدْرِى لَعَلَّهُۥ فِتْنَةٌۭ لَّكُمْ وَمَتَٰعٌ إِلَىٰ حِينٍۢ", transliteration: "Wain adree laAAallahu fitnatun lakum wamataAAun ila heenin", transliterationB: "Wa in adree la'allahoo fitnatul lakum wa mataa'un ilaaheen", english: "I know not but that it may be a trial for you, and a grant of (worldly) livelihood (to you) for a time", romanUrdu: "Main to yeh samajhta hoon ke shayad yeh (dair/delay) tumhare liye ek fitna hai aur tumhein ek waqt e khaas tak ke liye mazay karne ka mauqa diya jaa raha hai”" },
    { number: 112, arabic: "قَٰلَ رَبِّ ٱحْكُم بِٱلْحَقِّ ۗ وَرَبُّنَا ٱلرَّحْمَٰنُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ", transliteration: "Qala rabbi ohkum bialhaqqi warabbuna alrrahmanu almustaAAanu AAala ma tasifoona", transliterationB: "Qaala Rabbih kum bil haqq; wa Rabbunar Rahmaa nul musta'aanu 'alaa maa tasifoon", english: "Say: \"O my Lord! judge Thou in truth!\" \"Our Lord Most Gracious is the One Whose assistance should be sought against the blasphemies ye utter", romanUrdu: "(aakhi-e-kaar) Rasool ne kaha “aey mere Rubb, haqq ke saath faisla karde, aur logon, tum jo baatein banate ho unke muqable mein hamara Rubb-e-Rehman hi hamare liye madad ka sahara hai.”" }
  ]
};
